+func TestMatchCompletionPatternsConcurrent(t *testing.T) {
+	t.Parallel()
+
+	d := New("test-session", nil)
+
+	var wg sync.WaitGroup
+	for i := 0; i < 10; i++ {
+		wg.Add(1)
+		go func() {
+			defer wg.Done()
+			for j := 0; j < 50; j++ {
+				d.matchCompletionPatterns("task bd-1234 done successfully")
+				d.matchCompletionPatterns("no match here")
+			}
+		}()
+	}
+	wg.Wait()
+}
